const Q_CHEMISTRY_2011=[{"id": "objective>Chemistry>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject being done is Chemistry as all the questions are related to Chemistry.</div>", "topic": "INTRODUCTION TO CHEMISTRY"}, {"id": "objective>Chemistry>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the concentration of a solution containing 2g of NaOH in 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of solution?  <br/>  [Na = 23, O = 16, H = 1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.40 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.30 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Mass of NaOH in 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 2g ∴ Mass of NaOH in 1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> or 1,000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 1000/100 × 2 = 20g  <br/>  Recall the molar mass of NaOH = 40gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  Concentration in moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> = concentration in gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>/molar mass = 20/40 = 0.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following properties is NOT peculiar to matter?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kinetic energy of particles increases from solid to gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Random motion of particles increases from liquid to gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Orderliness of particles increases from gas to liquid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Random motion of particles increases from gas to solid</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Randomness has to do with the degree of disorderliness of a system. <br/> Random motion of particles does not  increase from gas to solid, rather it increases from solid to gas.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of column chromatography is based on the ability of the constituents to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">move at different speed in the column</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolve in each other in the column </div>", "<div style=\"font-family:Cambria;font-size:17px;\">react with the solvent in the column </div>", "<div style=\"font-family:Cambria;font-size:17px;\">react with each other in the column </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The physical property that forms the basis of operation in chromatography is the difference in the speed at which constituents move over an absorbent medium.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, an ideal gas can be represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that the slope of that graph is called the copressibility factor. <br/>  The compressiblity factor (C.F) for an ideal gas (PV/P) is a straight line graph which is parallel to the P-axis. </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is correct about the periodic table?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">None-metallic properties of the element tend to decrease across each period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The valence electrons of the elements increase progressively across the period </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Elements in the same group have the same number of electron shell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Element in the same period have the same number of valence electrons</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the periodic table, the valence electrons of the elements increase progressively across the period. This is because as you move from left to right across a period, each element has one more proton and one more electron than the previous element. The additional electron goes into the same outermost shell (also known as the valence shell), thus increasing the number of valence electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relative atomic mass of naturally occurring lithium consisting of 90% <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>Li and 10% <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>Li is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.9</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.8</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relative atomic mass of naturally occurring lithium can be calculated by taking a weighted average of the atomic masses of its isotopes. This gives (0.90 * 7) + (0.10 * 6) = 6.9.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An isotope has an atomic number of 15 and a mass number of 31. The number of protons it contains is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15</div>", "<div style=\"font-family:Cambria;font-size:17px;\">46</div>", "<div style=\"font-family:Cambria;font-size:17px;\">31</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Atomic number = 15 <br/> Mass number = 31 <br/> N.B: Atomic number = number of proton = 15 <br/> Mass number = number of proton + number of neutron <br/> 31 = 15 + number of neutron <br/> number of neutron = 16 <br/> Since the question asks for the number of proton <br/> ∴ n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 15</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The molecular lattice of iodine is held together by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dative bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic band</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">van der waal's force</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Van der Waals forces (or van der Waals' interaction) is the sum of the attractive or repulsive forces between molecules (or between parts of the same molecule) other than those due to covalent bonds, or the electrostatic interaction of ions with one another, with neutral molecules, or with charged molecules.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The arrangement of particles in crystal lattices can be studied using </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">x-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">γ-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">α-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">β-rays</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Crystallography is the experimental science of determining the arrangement of atoms in the crystalline solids. X-ray crystallography is the use of x-rays to study crystals.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  From the diagram above, find the amount of solute deposited when 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of solution is cooled from 55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.10 mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20 mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.01 mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.02 mol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the graph: <br/> <img src=\"2011/s22.png\" style=\"position:relative;max-width:100%;\"/> <br/>  At 55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C, the solubility of the salt is 6 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/>  At 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C, the solubility of the salt is 5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/>  When the solution is cooled from 55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C( 6-5) moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> = 1.0 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> will crystallize out. <br/>  1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 1000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, recall. <br/>  That is, 1mole of the salt is present in 1000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> when cooled from 55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>cm to 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C  <br/>  x mol of the salt is present in 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> when cooled from 55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C  <br/>  1/x = 1000/200; 1/x = 5/1; 5x = 1;  <br/> x = 0.2mole. </div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The importance of sodium aluminate (III) in the treatment of water is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cause coagulation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutralize acicity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent goitre and tooth decay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kill germs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In water treatment, it is used as an adjunct to water softening systems, as a coagulant aid to improve flocculation, and for removing dissolved silica and phosphates.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of bond exist between an element X with atomic number 12 and Y with atomic number 17?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electrovalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dative </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An element X with atomic number 12 is Magnesium (a metal) and Y with atomic number 17 is Chlorine (a non-metal). The bond between a metal and a non-metal is typically an ionic or electrovalent bond. In this bond, electrons are transferred from the metal to the non-metal.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hardness of water is mainly due to the presence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium hydroxide or magnesium hydroxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium trioxocarbonate (IV) or calcium tetraoxosulphate (VI) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide or magnesium hydroxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium chloride or sodium chloride salts</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Temporary hardness is a type of water hardness caused by the presence of dissolved minerals such as calcium and carbonate minerals. Permanent hardness is hardness that cannot be removed by boiling. When this is the case, it is usually caused by the presence of calcium sulphate and/or magnesium sulphates in the water, which do not precipitate out as the temperature increases.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A suitable solvent for iodine and naphthalene is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)sulphide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">benzene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Benzene is a suitable solvent for both iodine and naphthalene. Both iodine and naphthalene are non-polar substances, and according to the 'like dissolves like' rule, non-polar solvents like benzene are effective at dissolving non-polar solutes.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following noble gases is commonly found in the atmosphere?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Xenon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Helium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Argon</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Argon. Argon is a chemical element with symbol Ar and atomic number 18. It is in group 18 of the periodic table and is a noble gas.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(g)</span> ↔ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ∆H = +ve <br/>  In the reaction above, an increase in temperature will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the value in the equilibrium constant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the value of the equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the reactant production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift the equilibrium to left</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature will increase the value in the equilibrium constant.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>↔ CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span>  <br/>  In the reaction above,CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conjugate base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conjugate acid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a conjugate base. The conjugate base of an acid is formed when the acid donates a proton. In the equation, OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> is the conjugate base to the acid H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, because H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O donates a hydrogen ion to form OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>, the conjugate base.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many cations will be produced from a solution of potassium aluminium tetraoxosulphate (VI)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Two cations. KAL(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> comprises two cations, K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT an alkali?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An alkali is a basic, ionic salt of an alkali metal or alkaline earth metal chemical element. An alkali can also be defined as a base that dissolves in water to form hydroxide ions(OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>). Or a metallic hydroxide that is solube in water. NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (Ammonia) is a weak base, but it is not an alkali because it does not dissolve in water to form a solution.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An effect of thermal pollution on water bodies is that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volume of water reduces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume of chemical waste increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of oxides of nitrogen increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of oxygen reduces</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thermal pollution is the degradation of water quality by any process that changes ambient water temperature. A common cause of thermal pollution is the use of water as a coolant by power plants and industrial manufacturers. This raises the water temperature, which reduces the level of oxygen in the water, thereby affecting aquatic life.</div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a deliquesent compound?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaO</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deliquescent substances are those that absorb moisture from the air until they dissolve completely in the absorbed water and form a solution. Calcium chloride (CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) is a deliquescent compound.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A chemical reaction in which the hydration energy is greater than the lattice energy is reffered to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a spontaneous reaction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an endothermic reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an exothermic reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reversible reaction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A chemical reaction in which the hydration energy is greater than the lattice energy is referred to as an exothermic reaction. In an exothermic reaction, energy is released to the surroundings, usually in the form of heat. The hydration energy is the energy released when new bonds form between ions and water molecules. The lattice energy is the energy required to separate the ions in an ionic solid. If the hydration energy is greater than the lattice energy, the excess energy is released, making the reaction exothermic.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function of zinc electrode in galvanic cell is that it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">undergoes reduction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">serves as the positive electrode  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">produces electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uses up electrons</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a galvanic cell, the zinc electrode acts as the anode, which is the site of oxidation. During oxidation, zinc loses electrons to become zinc ions. Therefore, it produces electrons.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(g)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/>  The major factor that influences the rate of the reaction above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction given is the substitution reaction of alkanes, it is a photocatalytic reaction, that is, it occurs in the presence of light (ultra-violet light). The major factor will be light.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The condition required for corrosion to take place is the presence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water and carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water and carbon (IV) oxide and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen and carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water and oxygen </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Corrosion is a natural process, which converts refined metal to their more stable oxide. It is the gradual destruction of materials (usually metals) by chemical reaction with their environment. In the most common use of the word, this means electrochemical oxidation of metal in reaction with an oxidant such as oxygen, in the presence of water.</div>", "topic": "ELECTROLYSIS : CORROSION"}, {"id": "objective>Chemistry>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  In the diagram above, X is the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enthalpy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enthalpy change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activation energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activated complex</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the enthalpy change.\"X\" shows the difference between the heat contents of the products and reactants which is the enthalpy change. </div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  The diagram above best illustrates the effect of decrease in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">concentration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The graph indicates that the reaction rate decrease with time as the concentration decreases. In a chemical reaction the concentration of the reaction decreases with time, i.e the reaction rate decreases. </div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Y + 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> <br/>  In the equation above, Y is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction : MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + Y + 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> → Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  <br/>  The charge on both side should be balanced <br/>  <br/>  -1 + y + 5(2) ⇒ 2 + 5(3) <br/>  <br/>  -1 + y + 10 = 2 + 15 <br/>  <br/>  y + 9 = 17; y = 17 - 9  = 8 </div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that M is the mass of a substances deposited during electrolysis and Q is the quantity of electricity consumed, then Faraday's first law can be written as... <br/>  [E = Electrochemical equivalent]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M = E/Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M = EQ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M = Q/E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M = E/2Q </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Faraday's First Law of electrolysis,the mass (M) of a substance deposited at an electrode during electrolysis is directly proportional to the quantity of electricity (Q) passing through the electrolyte. <br/>  Note that E is the electrochemical equivalent.</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The impurities formed during the laboratory preparation of chlorine gas are removed by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The inpurity which is mainly HCl is removed by water because it is very soluble in water.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of the presence of impurities such as carbon and sulphur on iron is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">give it high tensile strength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make it malleable and ductile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase its melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower its melting point</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of impurities such as carbon and sulphur in iron lower its melting point. These impurities disrupt the regular arrangement of iron atoms, making it easier for the atoms to slide past each other and thus lowering the melting point.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A few drops of concentrated HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is added to an unknown solution and boiled for a while. If this produces a brown solution, the cation present is likely to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a few drops of concentrated HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is added to an unknown solution and boiled for a while, if it produces a brown solution, the cation present is likely to be Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span>. This is because Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> ions react with nitric acid to form brown nitrogen dioxide gas.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bleaching action of chlorine gas is effective due to the presence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrgen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water improves the bleaching action of chlorine gas.The bleaching action of chlorine is due to its abiliy to react with water to form oxochlorate(I) acid. The latter is unstable and decomposes to release oxygen which oxidizes the dye to from a colourless compound. </div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the laboratory preparation of oxygen, dried oxygen is usually collected over</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrochloric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetraoxosulphate (VI) acid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the laboratory preparation of oxygen, dried oxygen is usually collected over mercury. This is because mercury does not react with oxygen, and it provides a convenient way to collect the gas without introducing any additional moisture or impurities.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The property of concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> that makes it suitable for preparing HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">density </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidizing property</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydrating property </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> has very strong oxidizing properties. Trioxonitrate(V) acid can be displaced from any trioxonitrate (V) by concentrated tetraoxosulphates(VI) acids, which is a less volatile (a high boiling point) acid.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bronze is preferred to copper in the making of medals because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is stronger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can withstand low temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is lighter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has low tensile strength</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bronze is an alloy of copper and tin. It is preferred to copper in the making of medals because it is stronger than copper. The addition of tin to copper increases the strength of the resulting alloy, making it more durable and suitable for making medals.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The constituent of baking powder that makes the dough to rise is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is the main composition of baking powder. It is called sodium bicarbonate. It has a slightly salty, alkaline taste resembling that of washing soda; sodium carbonate.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds is used as a gaseous fuel?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> - C = CH</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is used. This is known as butane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of carbon to form long chains is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkylation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acylation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">catenation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbonation </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Catenation describes the linkage of atoms of the same element into longer chains. Catenation occurs most readily in carbon, which forms covalent bonds with other carbon atoms to form longer chains and structures. This is the reason for the presence of the vast number of organic compounds in nature.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">which of the following compounds will undergo polymerization reaction? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> (ethene) will. Polymerization is a process of reacting monomer molecules together in a chemical reaction to form polymer chains or three-dimensional networks.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The compound above exhibits</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">geometric isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">optical isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structural isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positional isomerism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Optical isomers are molecules that differ three-dimensionally by the placement of substituents around one or more atoms in a molecule. Optical isomers were given their name because they were first able to be distinguished by how they rotated plane-polarized light.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic compound has an empirical formula CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O and vapour density of 45. What is its molecular formula?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Relative molecular mass = 2 × vapour density = 2 × 45 = 90;  <br/> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 90  <br/>  (12 + 2 + 16)x = 90; 30x = 90; x = 3  <br/>  The molecular formula will be (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> 2C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH + 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + Energy  <br/>  The reaction represented by the equation above is useful in the production of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">butanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction show the production of ethanol; an alkanol.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of isomers that can be obtained from C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number of isomers for C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> is 2. They are butane and 2-methylpropane. Isomers are compounds with the same molecular formula but different structural formulas.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>   <br/>  The functional groups present in the background above are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkene and halo-group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydroxyl and chloro-group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkane and chloro-group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydroxyl and halo-group</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The functional groups present in the background above are the hydroxyl and halo-group.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a primary amine</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>NH</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is.  Primary amines arise when one of three hydrogen atoms in ammonia is replaced by an alkyl or aromatic.</div>", "topic": "ORGANIC COMPOUNDS : AMINES"}, {"id": "objective>Chemistry>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two organic compounds K and L were treated with a few drops of Fehling's solution respectively. K formed a brick-red precipitation while L remains unaffected. The compound K is an </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkanol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Compound K is an alkanal. Fehling's can be used to determine whether a carbonyl-containing compound is an aldehyde or a ketone. The bistartratocuprate(II) complex in Fehling's solution is an oxidizing agent and the active reagent in the test. The compound to be tested is added to the Fehling's solution and the mixture is heated. Aldehydes are oxidized, giving a positive result, but ketones do not react, unless they are alpha-hydroxy-ketones.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is true about 2-methylpropane and butane?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They are members of the same homologous series </div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have the same boiling points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have different number of carbon atoms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have the same chemical properties</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They are members of the same homologous series. Another property they have in common is the molecular formula, because they are isomers.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/>  The reaction above is best described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">esterification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">saponification </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutralization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Esterification is the general name for a chemical reaction in which two reactants (typically an alcohol and an  organic acid) form an ester as the reaction product. Esters are common in organic chemistry and biological materials, and often have a characteristic pleasant, fruity odor.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}];
